class CredentialManager(config: AwsServiceConfig) {

  private var cachedProvider: Option[AwsCredentialsProvider] = None
  private var assumedRoleProvider: Option[AwsCredentialsProvider] = None

  def getCredentialsProvider: AwsCredentialsProvider = {
    cachedProvider.getOrElse {
      val provider = config.credentialMode match {
        case StaticCredentials(accessKey, secretKey) =>
          StaticCredentialsProvider.create(
            AwsBasicCredentials.create(accessKey, secretKey)
          )

        case SessionCredentials(accessKey, secretKey, sessionToken) =>
          StaticCredentialsProvider.create(
            AwsSessionCredentials.create(accessKey, secretKey, sessionToken)
          )

        case ProfileBasedCredentials(profileName) =>
          ProfileCredentialsProvider.create(profileName)

        case DefaultCredentials =>
          DefaultCredentialsProvider.create()

        case AssumeRoleCredentials(roleArn, sessionName) =>
          assumedRoleProvider.getOrElse {
            val provider = resolveAssumeRoleCredentials(roleArn, sessionName)
            assumedRoleProvider = Some(provider)
            provider
          }
      }
      cachedProvider = Some(provider)
      provider
    }
  }

  private def resolveAssumeRoleCredentials(roleArn: String, sessionName: String): AwsCredentialsProvider = {
    val stsClient = StsClient.builder()
      .region(config.region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val assumeRoleRequest = AssumeRoleRequest.builder()
        .roleArn(roleArn)
        .roleSessionName(sessionName)
        .durationSeconds(3600)
        .build()

      val response = stsClient.assumeRole(assumeRoleRequest)
      val credentials = response.credentials()

      StaticCredentialsProvider.create(
        AwsSessionCredentials.create(
          credentials.accessKeyId(),
          credentials.secretAccessKey(),
          credentials.sessionToken()
        )
      )
    } finally {
      stsClient.close()
    }
  }

  def validateCredentials(): Try[String] = {
    Try {
      val stsClient = StsClient.builder()
        .region(config.region)
        .credentialsProvider(getCredentialsProvider)
        .build()

      try {
        val response = stsClient.getCallerIdentity(GetCallerIdentityRequest.builder().build())
        s"Authenticated as ARN: ${response.arn()}, Account: ${response.account()}"
      } finally {
        stsClient.close()
      }
    }
  }

  def refreshCredentials(): Unit = {
    cachedProvider = None
    assumedRoleProvider = None
  }
}

