    case Success(msg) => println(msg)
    case Failure(ex) => println(s"Failed to put object: ${ex.getMessage}")
  }

  manager.s3.getObject("my-bucket", "test-key") match {
    case Success(content) => println(s"Object content: $content")
    case Failure(ex) => println(s"Failed to get object: ${ex.getMessage}")
  }

  // SQS operations
  manager.sqs.sendMessage("https://sqs.us-east-1.amazonaws.com/123456789012/my-queue", "Test message") match {
    case Success(messageId) => println(s"Message sent with ID: $messageId")
    case Failure(ex) => println(s"Failed to send message: ${ex.getMessage}")
  }

  manager.sqs.receiveMessages("https://sqs.us-east-1.amazonaws.com/123456789012/my-queue") match {
    case Success(messages) =>
      messages.foreach { case (id, body, _) =>
        println(s"Received message $id: $body")
      }
    case Failure(ex) => println(s"Failed to receive messages: ${ex.getMessage}")
  }

  // DynamoDB operations
  manager.dynamoDb.putItem("my-table", Map("id" -> "1", "name" -> "Test Item", "value" -> "42")) match {
    case Success(msg) => println(msg)
    case Failure(ex) => println(s"Failed to put item: ${ex.getMessage}")
  }

  manager.dynamoDb.getItem("my-table", Map("id" -> "1")) match {
    case Success(Some(item)) => println(s"Retrieved item: $item")
    case Success(None) => println("Item not found")
    case Failure(ex) => println(s"Failed to get item: ${ex.getMessage}")
  }

  manager.dynamoDb.scanTable("my-table") match {
    case Success(items) =>
      items.foreach(item => println(s"Scanned item: $item"))
    case Failure(ex) => println(s"Failed to scan table: ${ex.getMessage}")
  }

